using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

namespace McpServer;

[McpServerToolType]
public sealed class WeatherTools
{
    private readonly IHttpClientFactory _httpClientFactory;

    public WeatherTools(IHttpClientFactory httpClientFactory)
    {
        _httpClientFactory = httpClientFactory;
    }

    [McpServerTool, Description("Get current weather for a location by latitude and longitude.")]
    public async Task<string> GetCurrentWeather(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude)
    {
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}&current=temperature_2m,wind_speed_10m";
        using var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        using var doc = JsonDocument.Parse(json);
        var current = doc.RootElement.GetProperty("current");

        var temp = current.GetProperty("temperature_2m").GetDouble();
        var wind = current.GetProperty("wind_speed_10m").GetDouble();

        return $"Temperature: {temp}°C, Wind: {wind} km/h";
    }

    [McpServerTool, Description("Get weather forecast for the next N days.")]
    public async Task<string> GetForecast(
        [Description("Latitude of the location")] double latitude,
        [Description("Longitude of the location")] double longitude,
        [Description("Number of forecast days (1-7)")] int days = 3)
    {
        days = Math.Clamp(days, 1, 7);
        using var client = _httpClientFactory.CreateClient("WeatherApi");

        var url = $"v1/forecast?latitude={latitude}&longitude={longitude}&daily=temperature_2m_max,temperature_2m_min&forecast_days={days}";
        using var response = await client.GetAsync(url);
        response.EnsureSuccessStatusCode();

        var json = await response.Content.ReadAsStringAsync();
        using var doc = JsonDocument.Parse(json);
        var daily = doc.RootElement.GetProperty("daily");

        var dates = daily.GetProperty("time").EnumerateArray().Select(e => e.GetString()).ToList();
        var maxTemps = daily.GetProperty("temperature_2m_max").EnumerateArray().Select(e => e.GetDouble()).ToList();
        var minTemps = daily.GetProperty("temperature_2m_min").EnumerateArray().Select(e => e.GetDouble()).ToList();

        var lines = dates.Select((date, i) => $"{date}: {minTemps[i]}°C - {maxTemps[i]}°C");
        return string.Join("\n", lines);
    }
}

